const headers = $json.headers ?? {};
const body = ($json.body && typeof $json.body === 'object' && !Array.isArray($json.body)) ? $json.body : $json;

const getHeader = (name) => {
  const lower = name.toLowerCase();
  return headers[lower] ?? headers[name] ?? headers[name.toUpperCase()] ?? '';
};

const headerSecret = getHeader('x-mobile-secret');
const expectedSecret = $env.MOBILE_WEBHOOK_SECRET ?? '';
const authorized = Boolean(expectedSecret) && headerSecret === expectedSecret;

const contentType = String(getHeader('content-type') || '').toLowerCase();
const isJsonContentType = contentType.includes('application/json');

const payloadIsObject = body && typeof body === 'object' && !Array.isArray(body);
const rawText = payloadIsObject && typeof body.text === 'string' ? body.text : '';
const rawUrl = payloadIsObject && typeof body.url === 'string' ? body.url : '';
let rawTags = payloadIsObject ? body.tags : [];
if (typeof rawTags === 'string') {
  rawTags = rawTags.split(',').map((t) => t.trim()).filter(Boolean);
}
if (!Array.isArray(rawTags)) {
  rawTags = [];
}
const tags = rawTags
  .map((tag) => (typeof tag === 'string' ? tag.trim() : String(tag ?? '').trim()))
  .filter(Boolean);

const source = payloadIsObject && typeof body.source === 'string' && body.source.trim()
  ? body.source.trim()
  : 'ios-shortcut';

const metaInput = payloadIsObject && body.meta && typeof body.meta === 'object' && !Array.isArray(body.meta)
  ? body.meta
  : {};

const normalized = {
  text: rawText.trim(),
  url: rawUrl.trim(),
  tags,
  source,
  meta: {
    sentAt: typeof metaInput.sentAt === 'string' && metaInput.sentAt.trim() ? metaInput.sentAt : null,
    device: typeof metaInput.device === 'string' && metaInput.device.trim() ? metaInput.device : null
  }
};

return [{
  json: {
    authorized,
    isJsonContentType,
    payloadValid: payloadIsObject,
    normalized,
    receivedAt: new Date().toISOString()
  }
}];

const data = $getWorkflowStaticData('global');
if (!Array.isArray(data.mobileInboxLog)) data.mobileInboxLog = [];

const entry = {
  receivedAt: $json.receivedAt,
  text: $json.normalized.text,
  url: $json.normalized.url,
  tags: $json.normalized.tags,
  source: $json.normalized.source,
  meta: $json.normalized.meta
};

data.mobileInboxLog.push(entry);
if (data.mobileInboxLog.length > 200) {
  data.mobileInboxLog = data.mobileInboxLog.slice(-200);
}

return [{
  json: {
    ok: true,
    receivedAt: $json.receivedAt,
    echo: {
      text: entry.text,
      url: entry.url,
      tags: entry.tags,
      source: entry.source
    }
  }
}];
